import { useState, useRef, useEffect, useCallback } from "react";

/* ───────── BRAND ───────── */
const B = {
  burnham:"#2B5040", whiteSmoke:"#F5F0E8", wisteria:"#C9B2CB",
  tangerine:"#FF6347", yellowGreen:"#A5C32C", celadon:"#87C4A0",
  ash:"#B8B0A8", jet:"#2D2D2D",
};
const FONT_URL = "https://fonts.googleapis.com/css2?family=Syne:wght@400;500;600;700;800&family=Fira+Sans:ital,wght@0,300;0,400;0,500;0,600;0,700;1,400;1,500&family=Cormorant+Garamond:ital,wght@0,400;0,600;1,400;1,500&family=Aboreto&display=swap";
const F = {
  title:"'Cormorant Garamond',Georgia,serif",
  quote:"'Cormorant Garamond',Georgia,serif",
  subtitle:"'Syne','Helvetica Neue',sans-serif",
  body:"'Fira Sans','Helvetica Neue',sans-serif",
  logo:"'Aboreto',sans-serif",
};
const POST_TYPES = [
  {id:"photo_logo",label:"Photo + Logo",needsImage:true},
  {id:"quote",label:"Quote",needsImage:false},
  {id:"event",label:"Event / Date",needsImage:true},
  {id:"text_post",label:"Text Post",needsImage:false},
  {id:"texture_text",label:"Photo + Text",needsImage:true},
];
const BG_OPTIONS = [
  {id:"burnham",label:"Burnham",color:B.burnham,light:true},
  {id:"whiteSmoke",label:"White Smoke",color:B.whiteSmoke,light:false},
  {id:"wisteria",label:"Wisteria",color:B.wisteria,light:false},
  {id:"celadon",label:"Celadon",color:B.celadon,light:false},
  {id:"jet",label:"Jet",color:B.jet,light:true},
];
const PRESETS = {
  "top-left":[0.12,0.12],"top-center":[0.50,0.12],"top-right":[0.88,0.12],
  "center":[0.50,0.50],
  "bottom-left":[0.12,0.88],"bottom-center":[0.50,0.88],"bottom-right":[0.88,0.88],
};

const SAMPLE_IMAGES = [
  {label:"Children running",thumb:"data:image/jpeg;base64,",full:"data:image/jpeg;base64,"},
  {label:"Art with orchids",thumb:"data:image/jpeg;base64,",full:"data:image/jpeg;base64,"},
  {label:"Movement class",thumb:"data:image/jpeg;base64,",full:"data:image/jpeg;base64,"},
  {label:"Cooking class",thumb:"data:image/jpeg;base64,",full:"data:image/jpeg;base64,"},
  {label:"Chess club",thumb:"data:image/jpeg;base64,",full:"data:image/jpeg;base64,"},
];

/* ───────── HELPERS ───────── */
function wrapText(ctx,text,x,y,maxW,lh){const words=text.split(" ");let line="";const lines=[];for(let i=0;i<words.length;i++){const t=line+words[i]+" ";if(ctx.measureText(t).width>maxW&&i>0){lines.push(line.trim());line=words[i]+" ";}else line=t;}lines.push(line.trim());lines.forEach((l,i)=>ctx.fillText(l,x,y+i*lh));return lines.length;}
function drawArrow(ctx,x,y,w,color){ctx.save();ctx.strokeStyle=color;ctx.lineWidth=2.5;ctx.lineCap="round";ctx.beginPath();ctx.moveTo(x,y);ctx.lineTo(x+w,y);ctx.moveTo(x+w-10,y-6);ctx.lineTo(x+w,y);ctx.lineTo(x+w-10,y+6);ctx.stroke();ctx.restore();}
function coverDraw(ctx,img,w,h){const s=Math.max(w/img.width,h/img.height);ctx.drawImage(img,(w-img.width*s)/2,(h-img.height*s)/2,img.width*s,img.height*s);}
function containDraw(ctx,img,cx,cy,mW,mH,a){const s=Math.min(mW/img.width,mH/img.height);ctx.save();ctx.globalAlpha=a;ctx.drawImage(img,cx-(img.width*s)/2,cy-(img.height*s)/2,img.width*s,img.height*s);ctx.restore();}
function imgFrom(d){return new Promise(r=>{const i=new Image();i.onload=()=>r(i);i.onerror=()=>r(null);i.src=d;});}

/* ───────── IMAGE COMPRESSION (browser-side) ───────── */
function compressImage(dataUrl, maxSize, quality) {
  return new Promise(resolve => {
    const img = new Image();
    img.onload = () => {
      const c = document.createElement("canvas");
      const s = Math.min(img.width, img.height);
      const sx = (img.width - s) / 2, sy = (img.height - s) / 2;
      c.width = maxSize; c.height = maxSize;
      c.getContext("2d").drawImage(img, sx, sy, s, s, 0, 0, maxSize, maxSize);
      resolve(c.toDataURL("image/jpeg", quality));
    };
    img.src = dataUrl;
  });
}

/* ───────── STORAGE ───────── */
const SK_LOGOS = "wo-brand-logos-v2";
const SK_LIB = "wo-image-library";
const SK_HIST = "wo-asset-history";
const MAX_LIB = 15;
const MAX_HIST = 20;

async function sGet(k) { try { const v = localStorage.getItem(k); return v ? JSON.parse(v) : null; } catch(e) { return null; } }
async function sSet(k, v) { try { localStorage.setItem(k, JSON.stringify(v)); } catch(e) { console.error("Storage error:", e); } }
async function sDel(k) { try { localStorage.removeItem(k); } catch(e) {} }

/* ───────── MAIN ───────── */
export default function App() {
  const SIZE = 1080;
  const canvasRef = useRef(null);
  const previewRef = useRef(null);
  const imgRef = useRef(null);
  const iconRef = useRef(null);
  const wmRef = useRef(null);

  const [ready, setReady] = useState(false);
  const [fontsLoaded, setFontsLoaded] = useState(false);
  const [postType, setPostType] = useState("photo_logo");
  const [bgColor, setBgColor] = useState("burnham");
  const [image, setImage] = useState(null);
  const [imageObj, setImageObj] = useState(null);
  const [iconData, setIconData] = useState(null);
  const [iconObj, setIconObj] = useState(null);
  const [wmData, setWmData] = useState(null);
  const [wmObj, setWmObj] = useState(null);
  const [activeSlot, setActiveSlot] = useState("icon");
  const [headline, setHeadline] = useState("");
  const [subtext, setSubtext] = useState("");
  const [attribution, setAttribution] = useState("");
  const [dateText, setDateText] = useState("");
  const [logoX, setLogoX] = useState(0.88);
  const [logoY, setLogoY] = useState(0.88);
  const [logoSc, setLogoSc] = useState(25);
  const [logoOp, setLogoOp] = useState(100);
  const [dragging, setDragging] = useState(false);

  // Library & History
  const [library, setLibrary] = useState([]); // [{id, thumb, full}]
  const [history, setHistory] = useState([]); // [{id, thumb, label, date}]
  const [libOpen, setLibOpen] = useState(false);
  const [histOpen, setHistOpen] = useState(false);

  const curType = POST_TYPES.find(t => t.id === postType);
  const curBg = BG_OPTIONS.find(b => b.id === bgColor);
  const tc = curBg?.light ? B.whiteSmoke : B.jet;
  const logo = activeSlot === "wordmark" ? wmObj : iconObj;
  const showLogoCtrl = postType === "photo_logo" || postType === "texture_text";

  /* ── Load fonts ── */
  useEffect(() => {
    const link = document.createElement("link");
    link.href = FONT_URL; link.rel = "stylesheet";
    document.head.appendChild(link);
    document.fonts.ready.then(() => setFontsLoaded(true));
    return () => { try { document.head.removeChild(link); } catch(e){} };
  }, []);

  /* ── Load everything from storage ── */
  useEffect(() => {
    (async () => {
      const logos = await sGet(SK_LOGOS);
      if (logos?.icon) { setIconData(logos.icon); setIconObj(await imgFrom(logos.icon)); }
      if (logos?.wordmark) { setWmData(logos.wordmark); setWmObj(await imgFrom(logos.wordmark)); }
      const lib = await sGet(SK_LIB);
      if (lib) setLibrary(lib);
      const hist = await sGet(SK_HIST);
      if (hist) setHistory(hist);
      setReady(true);
    })();
  }, []);

  /* ── Save logos ── */
  useEffect(() => { if (ready) sSet(SK_LOGOS, {icon:iconData,wordmark:wmData}); }, [iconData, wmData, ready]);

  /* ── Save library to storage when it changes ── */
  useEffect(() => { if (ready && library.length >= 0) sSet(SK_LIB, library); }, [library, ready]);

  /* ── Save history to storage when it changes ── */
  useEffect(() => { if (ready && history.length >= 0) sSet(SK_HIST, history); }, [history, ready]);

  /* ── Upload handlers ── */
  const uploadLogo = (file, slot) => {
    if (!file) return;
    const r = new FileReader();
    r.onload = async (e) => {
      const d = e.target.result, img = await imgFrom(d);
      if (slot==="icon"){setIconData(d);setIconObj(img);}else{setWmData(d);setWmObj(img);}
    };
    r.readAsDataURL(file);
  };
  const rmLogo = s => { if(s==="icon"){setIconData(null);setIconObj(null);}else{setWmData(null);setWmObj(null);} };

  /* ── Load image + auto-save to library ── */
  const loadImage = useCallback(async (dataUrl) => {
    setImage(dataUrl);
    setImageObj(await imgFrom(dataUrl));
    // Compress and save to library
    const thumb = await compressImage(dataUrl, 120, 0.5);
    const full = await compressImage(dataUrl, 1080, 0.7);
    const id = Date.now().toString(36);
    setLibrary(prev => {
      const next = [{id, thumb, full}, ...prev.filter(x => x.full !== full)];
      return next.slice(0, MAX_LIB);
    });
  }, []);

  const loadFile = useCallback((file) => {
    if (!file) return;
    const r = new FileReader();
    r.onload = (e) => loadImage(e.target.result);
    r.readAsDataURL(file);
  }, [loadImage]);

  const selectLibraryImage = async (item) => {
    setImage(item.full);
    setImageObj(await imgFrom(item.full));
  };

  const removeLibraryItem = (id) => {
    setLibrary(prev => prev.filter(x => x.id !== id));
  };

  const clearHistory = () => setHistory([]);

  /* ── Presets ── */
  const applyPreset = k => { const [x,y]=PRESETS[k]; setLogoX(x); setLogoY(y); };
  const activePreset = Object.entries(PRESETS).find(([,v])=>Math.abs(v[0]-logoX)<0.03&&Math.abs(v[1]-logoY)<0.03)?.[0]||null;

  /* ── Drag + scroll ── */
  const toCanvas = (cx,cy) => {
    const el=previewRef.current; if(!el) return [0.5,0.5];
    const r=el.getBoundingClientRect();
    return [Math.max(0,Math.min(1,(cx-r.left)/r.width)),Math.max(0,Math.min(1,(cy-r.top)/r.height))];
  };
  const onPtrDown = e => { if(!showLogoCtrl) return; e.preventDefault(); setDragging(true); const [x,y]=toCanvas(e.clientX,e.clientY); setLogoX(x);setLogoY(y); previewRef.current?.setPointerCapture(e.pointerId); };
  const onPtrMove = e => { if(!dragging) return; const [x,y]=toCanvas(e.clientX,e.clientY); setLogoX(x);setLogoY(y); };
  const onPtrUp = e => { setDragging(false); previewRef.current?.releasePointerCapture(e.pointerId); };
  const onWheel = e => { if(!showLogoCtrl) return; e.preventDefault(); setLogoSc(p=>Math.max(5,Math.min(80,p-e.deltaY*0.05))); };

  /* ───────── CANVAS RENDER ───────── */
  const draw = useCallback(() => {
    const c=canvasRef.current; if(!c) return;
    const ctx=c.getContext("2d");
    const w=SIZE,h=SIZE;
    ctx.clearRect(0,0,w,h);
    const m=w*0.12, lSz=w*(logoSc/100), lx=logoX*w, ly=logoY*h;
    const putLogo=(cx,cy,sz,a)=>{if(logo)containDraw(ctx,logo,cx,cy,sz,sz,a);};
    const pattern=a=>{if(!logo)return;containDraw(ctx,logo,w*0.16,h*0.16,w*0.28,w*0.28,a*0.5);containDraw(ctx,logo,w*0.84,h*0.84,w*0.34,w*0.34,a);containDraw(ctx,logo,w*0.82,h*0.14,w*0.15,w*0.15,a*0.35);};
    const blank=msg=>{ctx.fillStyle=B.whiteSmoke;ctx.fillRect(0,0,w,h);ctx.fillStyle=B.burnham;ctx.font=`400 24px ${F.body}`;ctx.textAlign="center";ctx.fillText(msg,w/2,h/2);ctx.textAlign="left";};

    if(postType==="photo_logo"){
      if(imageObj)coverDraw(ctx,imageObj,w,h);else blank("Drop an image to begin");
      putLogo(lx,ly,lSz,logoOp/100);
    }else if(postType==="quote"){
      ctx.fillStyle=curBg.color;ctx.fillRect(0,0,w,h);pattern(0.10);
      const q=headline||"\u201CThe mind is not a vessel to be filled, but a fire to be kindled.\u201D";
      ctx.fillStyle=tc;ctx.font=`italic 500 64px ${F.quote}`;ctx.textAlign="left";
      const nl=wrapText(ctx,q,m,h*0.26,w-m*2,86);
      if(attribution||subtext){ctx.font=`600 22px ${F.subtitle}`;ctx.letterSpacing="3px";ctx.fillText((attribution||subtext).toUpperCase(),m,h*0.26+nl*86+56);ctx.letterSpacing="0px";}
    }else if(postType==="event"){
      if(imageObj){coverDraw(ctx,imageObj,w,h);ctx.fillStyle=curBg.color+"CC";ctx.fillRect(0,0,w,h);}else{ctx.fillStyle=curBg.color;ctx.fillRect(0,0,w,h);}
      if(headline){ctx.fillStyle=tc;ctx.font=`700 26px ${F.subtitle}`;ctx.textAlign="left";ctx.letterSpacing="2px";wrapText(ctx,headline.toUpperCase(),m,h*0.18,w-m*2,38);ctx.letterSpacing="0px";}
      if(dateText){const parts=dateText.split(" ");ctx.fillStyle=tc;ctx.font=`300 200px ${F.title}`;ctx.textAlign="left";ctx.fillText(parts[0]||"",m,h*0.62);ctx.font=`600 28px ${F.subtitle}`;ctx.letterSpacing="4px";ctx.fillText((parts.slice(1).join(" ")||"").toUpperCase(),m,h*0.70);ctx.letterSpacing="0px";}
      if(subtext){ctx.fillStyle=tc;ctx.font=`400 20px ${F.body}`;ctx.textAlign="left";wrapText(ctx,subtext,m,h*0.82,w-m*2,30);drawArrow(ctx,m,h*0.92,w*0.22,tc);}
    }else if(postType==="text_post"){
      ctx.fillStyle=curBg.color;ctx.fillRect(0,0,w,h);pattern(0.08);
      let y=h*0.30;
      if(subtext){ctx.fillStyle=tc;ctx.font=`italic 400 42px ${F.quote}`;ctx.textAlign="left";y+=wrapText(ctx,subtext,m,y,w-m*2,56)*56+12;}
      if(headline){ctx.fillStyle=tc;ctx.font=`700 62px ${F.subtitle}`;ctx.textAlign="left";y+=wrapText(ctx,headline.toUpperCase(),m,y,w-m*2,76)*76+24;}
      if(attribution){ctx.fillStyle=tc;ctx.font=`400 20px ${F.body}`;ctx.textAlign="left";wrapText(ctx,attribution,m,y+16,w-m*2,28);}
      drawArrow(ctx,m,h*0.89,w*0.24,curBg?.light?B.whiteSmoke:B.burnham);
    }else if(postType==="texture_text"){
      if(imageObj)coverDraw(ctx,imageObj,w,h);else blank("Drop an image to begin");
      if(logo)containDraw(ctx,logo,lx,ly,lSz,lSz,logoOp/100);
      if(headline){ctx.save();ctx.fillStyle=B.whiteSmoke;ctx.font=`700 48px ${F.subtitle}`;ctx.textAlign="right";ctx.shadowColor="rgba(0,0,0,0.45)";ctx.shadowBlur=16;ctx.letterSpacing="3px";ctx.fillText(headline.toUpperCase(),w-m,h*0.88);ctx.restore();}
    }
  },[postType,bgColor,imageObj,logo,headline,subtext,attribution,dateText,logoX,logoY,logoOp,logoSc,curBg,tc]);

  useEffect(()=>{if(fontsLoaded)draw();},[draw,fontsLoaded]);

  /* ── Download + save to history ── */
  const download = async () => {
    const c = canvasRef.current; if (!c) return;
    const slug = headline ? headline.toLowerCase().replace(/[^a-z0-9]+/g,"-").slice(0,30) : postType;
    // Download
    const a = document.createElement("a");
    a.download = `white-orchid-${slug}.png`;
    a.href = c.toDataURL("image/png");
    a.click();
    // Save thumbnail to history
    const thumbCanvas = document.createElement("canvas");
    thumbCanvas.width = 120; thumbCanvas.height = 120;
    thumbCanvas.getContext("2d").drawImage(c, 0, 0, 120, 120);
    const thumb = thumbCanvas.toDataURL("image/jpeg", 0.6);
    const label = headline || subtext || postType.replace(/_/g," ");
    const id = Date.now().toString(36);
    const date = new Date().toLocaleDateString("en-GB",{day:"numeric",month:"short"});
    setHistory(prev => [{id, thumb, label, date}, ...prev].slice(0, MAX_HIST));
  };

  if(!ready) return <div style={{height:"100vh",display:"flex",alignItems:"center",justifyContent:"center",background:B.whiteSmoke,fontFamily:F.body,color:B.burnham}}>Loading...</div>;

  /* ───────── UI ───────── */
  return (
    <div style={{fontFamily:F.body,color:B.jet,minHeight:"100vh",background:B.whiteSmoke}}>
      <div style={{padding:"20px 28px 16px",background:B.burnham,display:"flex",alignItems:"baseline",gap:12}}>
        <span style={{fontFamily:F.logo,fontSize:13,letterSpacing:3,color:B.whiteSmoke,textTransform:"uppercase"}}>The White Orchid</span>
        <span style={{fontFamily:F.subtitle,fontSize:15,fontWeight:500,color:B.celadon}}>Social Media Generator</span>
      </div>

      <div style={{display:"flex",flexWrap:"wrap"}}>
        {/* ── CONTROLS ── */}
        <div style={{flex:"1 1 310px",minWidth:270,maxWidth:410,padding:"22px 28px",borderRight:`1px solid ${B.ash}33`,background:"#fff",overflowY:"auto",maxHeight:"calc(100vh - 60px)"}}>

          <Sec label="Post Type">
            <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
              {POST_TYPES.map(t=><Chip key={t.id} on={postType===t.id} click={()=>setPostType(t.id)}>{t.label}</Chip>)}
            </div>
          </Sec>

          <Sec label="Brand Logos">
            <div style={{display:"flex",gap:12,marginBottom:10}}>
              <LogoSlot label="Icon" data={iconData} inputRef={iconRef} onUpload={f=>uploadLogo(f,"icon")} onRemove={()=>rmLogo("icon")} />
              <LogoSlot label="Wordmark" data={wmData} inputRef={wmRef} onUpload={f=>uploadLogo(f,"wordmark")} onRemove={()=>rmLogo("wordmark")} />
            </div>
            {(iconData||wmData)&&<div style={{display:"flex",gap:6,alignItems:"center"}}>
              <span style={{fontSize:12,fontFamily:F.subtitle,color:B.ash}}>Use:</span>
              {iconData&&<Chip on={activeSlot==="icon"} click={()=>setActiveSlot("icon")} sm>Icon</Chip>}
              {wmData&&<Chip on={activeSlot==="wordmark"} click={()=>setActiveSlot("wordmark")} sm>Wordmark</Chip>}
            </div>}
          </Sec>

          {(postType==="quote"||postType==="text_post"||postType==="event")&&(
            <Sec label="Background">
              <div style={{display:"flex",gap:10}}>
                {BG_OPTIONS.map(b=>(
                  <button key={b.id} onClick={()=>setBgColor(b.id)} title={b.label} style={{
                    width:36,height:36,borderRadius:"50%",cursor:"pointer",transition:"all 0.15s",
                    background:b.color,transform:bgColor===b.id?"scale(1.15)":"scale(1)",
                    border:bgColor===b.id?`3px solid ${B.burnham}`:`2px solid ${B.ash}66`,
                    boxShadow:bgColor===b.id?"0 0 0 2px #fff inset":"none",
                  }} />
                ))}
              </div>
              <div style={{fontSize:12,color:B.ash,marginTop:6,fontFamily:F.subtitle}}>{curBg?.label}</div>
            </Sec>
          )}

          {/* IMAGE SECTION */}
          {curType?.needsImage&&(
            <Sec label="Image">
              {/* Samples row */}
              <div style={{marginBottom:8}}>
                <div style={{fontSize:11,color:B.ash,marginBottom:5,fontFamily:F.subtitle,fontWeight:600}}>Samples</div>
                <div style={{display:"flex",gap:5,overflowX:"auto",paddingBottom:4}}>
                  {SAMPLE_IMAGES.map((s,i)=>(
                    <button key={i} onClick={()=>{setImage(s.full);imgFrom(s.full).then(setImageObj);}}
                      style={{flexShrink:0,width:48,height:48,borderRadius:6,border:image===s.full?`2px solid ${B.burnham}`:"2px solid transparent",padding:0,cursor:"pointer",overflow:"hidden",background:"none"}}
                      title={s.label}>
                      <img src={s.thumb} alt={s.label} style={{width:"100%",height:"100%",objectFit:"cover",display:"block",borderRadius:4}} />
                    </button>
                  ))}
                </div>
              </div>

              {/* My Library */}
              {library.length>0&&(
                <div style={{marginBottom:8}}>
                  <button onClick={()=>setLibOpen(!libOpen)} style={{fontSize:11,color:B.burnham,background:"none",border:"none",cursor:"pointer",fontFamily:F.subtitle,fontWeight:600,padding:0,marginBottom:5,display:"flex",alignItems:"center",gap:4}}>
                    My Library ({library.length}) <span style={{fontSize:9,transform:libOpen?"rotate(180deg)":"rotate(0deg)",transition:"transform 0.2s"}}>▼</span>
                  </button>
                  {libOpen&&(
                    <div style={{display:"flex",gap:5,flexWrap:"wrap",paddingBottom:4}}>
                      {library.map(item=>(
                        <div key={item.id} style={{position:"relative",flexShrink:0}}>
                          <button onClick={()=>selectLibraryImage(item)}
                            style={{width:48,height:48,borderRadius:6,border:image===item.full?`2px solid ${B.burnham}`:"2px solid transparent",padding:0,cursor:"pointer",overflow:"hidden",background:"none"}}>
                            <img src={item.thumb} alt="" style={{width:"100%",height:"100%",objectFit:"cover",display:"block",borderRadius:4}} />
                          </button>
                          <button onClick={()=>removeLibraryItem(item.id)}
                            style={{position:"absolute",top:-4,right:-4,width:16,height:16,borderRadius:"50%",background:B.jet,color:"#fff",border:"none",cursor:"pointer",fontSize:10,display:"flex",alignItems:"center",justifyContent:"center",lineHeight:1}}>×</button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}

              {/* Upload / current */}
              {!image?(
                <div onDrop={e=>{e.preventDefault();const f=e.dataTransfer.files?.[0];if(f?.type.startsWith("image/"))loadFile(f);}}
                  onDragOver={e=>e.preventDefault()} onClick={()=>imgRef.current?.click()}
                  style={{border:`2px dashed ${B.ash}66`,borderRadius:12,padding:"24px 14px",textAlign:"center",cursor:"pointer",background:`${B.whiteSmoke}88`}}>
                  <div style={{fontSize:14,color:B.burnham,fontFamily:F.subtitle,fontWeight:500}}>Drop a Midjourney image</div>
                  <div style={{fontSize:12,color:B.ash,marginTop:4}}>or click to browse</div>
                </div>
              ):(
                <div style={{position:"relative"}}>
                  <img src={image} alt="" style={{width:"100%",borderRadius:10,display:"block"}} />
                  <button onClick={()=>{setImage(null);setImageObj(null);}} style={xBtnAbs}>×</button>
                </div>
              )}
              <input ref={imgRef} type="file" accept="image/*" onChange={e=>{const f=e.target.files?.[0];if(f)loadFile(f);}} style={{display:"none"}} />
            </Sec>
          )}

          {showLogoCtrl&&(
            <Sec label="Logo Placement">
              <div style={{display:"flex",alignItems:"flex-start",gap:16,marginBottom:12}}>
                <PosGrid value={activePreset} onChange={applyPreset} />
                <div style={{flex:1,fontSize:11,color:B.ash,lineHeight:1.5,paddingTop:2}}>
                  Click preset or drag<br/>directly on preview.<br/>Scroll to resize.
                </div>
              </div>
              <Slider label="Size" min={5} max={80} val={logoSc} set={setLogoSc} />
              <Slider label="Opacity" min={10} max={100} val={logoOp} set={setLogoOp} />
            </Sec>
          )}

          <Sec label="Content">
            {postType==="quote"&&<><Area placeholder="Quote text" value={headline} onChange={e=>setHeadline(e.target.value)} /><In placeholder="Attribution" value={attribution} onChange={e=>setAttribution(e.target.value)} mt /></>}
            {postType==="event"&&<><In placeholder="Event title" value={headline} onChange={e=>setHeadline(e.target.value)} /><In placeholder="Date (e.g. 15 January)" value={dateText} onChange={e=>setDateText(e.target.value)} mt /><In placeholder="Details / CTA" value={subtext} onChange={e=>setSubtext(e.target.value)} mt /></>}
            {postType==="text_post"&&<><In placeholder="Intro line" value={subtext} onChange={e=>setSubtext(e.target.value)} /><In placeholder="Headline" value={headline} onChange={e=>setHeadline(e.target.value)} mt /><In placeholder="Subtext" value={attribution} onChange={e=>setAttribution(e.target.value)} mt /></>}
            {postType==="texture_text"&&<In placeholder="Overlay text (e.g. NOW OPEN)" value={headline} onChange={e=>setHeadline(e.target.value)} />}
            {postType==="photo_logo"&&<p style={{fontSize:13,color:B.ash,margin:0}}>No text. The orchid overlays your photo.</p>}
          </Sec>

          <button onClick={download} style={{
            width:"100%",padding:"14px 40px",background:B.tangerine,color:"#fff",
            border:"none",borderRadius:40,fontSize:14,fontWeight:700,cursor:"pointer",
            letterSpacing:2,textTransform:"uppercase",fontFamily:F.subtitle,marginTop:6,
          }}>Download PNG</button>
          <div style={{fontSize:11,color:B.ash,textAlign:"center",marginTop:6}}>1080 × 1080 px</div>

          {/* ASSET HISTORY */}
          {history.length>0&&(
            <div style={{marginTop:20,paddingTop:16,borderTop:`1px solid ${B.ash}33`}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
                <button onClick={()=>setHistOpen(!histOpen)} style={{fontSize:10,fontFamily:F.subtitle,fontWeight:700,letterSpacing:2.5,textTransform:"uppercase",color:B.ash,background:"none",border:"none",cursor:"pointer",padding:0,display:"flex",alignItems:"center",gap:4}}>
                  Recent Exports ({history.length}) <span style={{fontSize:9,transform:histOpen?"rotate(180deg)":"rotate(0deg)",transition:"transform 0.2s"}}>▼</span>
                </button>
                {histOpen&&<button onClick={clearHistory} style={{fontSize:11,color:B.tangerine,background:"none",border:"none",cursor:"pointer",fontFamily:F.body}}>Clear all</button>}
              </div>
              {histOpen&&(
                <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill, minmax(64px, 1fr))",gap:8}}>
                  {history.map(h=>(
                    <div key={h.id} style={{textAlign:"center"}}>
                      <div style={{width:"100%",aspectRatio:"1/1",borderRadius:6,overflow:"hidden",border:`1px solid ${B.ash}33`}}>
                        <img src={h.thumb} alt={h.label} style={{width:"100%",height:"100%",objectFit:"cover",display:"block"}} />
                      </div>
                      <div style={{fontSize:9,color:B.ash,marginTop:3,fontFamily:F.body,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{h.date}</div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </div>

        {/* ── PREVIEW ── */}
        <div style={{flex:"1 1 400px",padding:"22px 28px",display:"flex",flexDirection:"column",alignItems:"center",background:B.whiteSmoke}}>
          <div style={{fontSize:11,fontFamily:F.subtitle,fontWeight:600,letterSpacing:2,textTransform:"uppercase",color:B.ash,marginBottom:10,alignSelf:"flex-start"}}>Preview</div>
          <div ref={previewRef} onPointerDown={onPtrDown} onPointerMove={onPtrMove} onPointerUp={onPtrUp} onPointerCancel={onPtrUp} onWheel={onWheel}
            style={{width:"100%",maxWidth:540,aspectRatio:"1/1",borderRadius:8,overflow:"hidden",boxShadow:"0 4px 30px rgba(43,80,64,0.10)",background:B.whiteSmoke,cursor:showLogoCtrl?(dragging?"grabbing":"grab"):"default",touchAction:showLogoCtrl?"none":"auto"}}>
            <canvas ref={canvasRef} width={SIZE} height={SIZE} style={{width:"100%",height:"100%",display:"block",pointerEvents:"none"}} />
          </div>
          {showLogoCtrl&&<p style={{fontSize:11,color:B.ash,marginTop:8,textAlign:"center"}}>Drag to move logo · Scroll to resize</p>}
        </div>
      </div>
    </div>
  );
}

/* ── UI Atoms ── */
const FU={subtitle:"'Syne','Helvetica Neue',sans-serif",body:"'Fira Sans','Helvetica Neue',sans-serif"};
const xBtnAbs={position:"absolute",top:6,right:6,width:24,height:24,borderRadius:"50%",background:"rgba(0,0,0,0.45)",color:"#fff",border:"none",cursor:"pointer",fontSize:14,display:"flex",alignItems:"center",justifyContent:"center"};

function LogoSlot({label,data,inputRef,onUpload,onRemove}){
  return <div style={{flex:1}}>
    <div style={{fontSize:11,fontFamily:FU.subtitle,fontWeight:600,color:"#888",marginBottom:5}}>{label}</div>
    {data?(<div style={{position:"relative",height:64,borderRadius:8,border:`1px solid ${B.ash}44`,background:"#FAFAF7",display:"flex",alignItems:"center",justifyContent:"center"}}>
      <img src={data} alt="" style={{maxHeight:50,maxWidth:"85%",objectFit:"contain"}} />
      <button onClick={onRemove} style={{position:"absolute",top:3,right:3,width:20,height:20,borderRadius:"50%",background:"rgba(0,0,0,0.4)",color:"#fff",border:"none",cursor:"pointer",fontSize:12,display:"flex",alignItems:"center",justifyContent:"center"}}>×</button>
    </div>):(<div onClick={()=>inputRef.current?.click()} style={{height:64,border:`2px dashed ${B.ash}55`,borderRadius:8,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",background:"#FAFAF7"}}>
      <span style={{fontSize:20,color:B.ash}}>+</span>
    </div>)}
    <input ref={inputRef} type="file" accept="image/*,.svg" onChange={e=>onUpload(e.target.files?.[0])} style={{display:"none"}} />
  </div>;
}
function PosGrid({value,onChange}){
  const grid=[["top-left","top-center","top-right"],[null,"center",null],["bottom-left","bottom-center","bottom-right"]];
  return <div style={{display:"inline-grid",gridTemplateColumns:"repeat(3,1fr)",gap:3,background:`${B.ash}22`,borderRadius:8,padding:4}}>
    {grid.flat().map((pos,i)=>{if(!pos)return<div key={i} style={{width:30,height:30}}/>;const on=value===pos;
    return<button key={pos} onClick={()=>onChange(pos)} title={pos.replace(/-/g," ")} style={{width:30,height:30,borderRadius:6,border:"none",cursor:"pointer",background:on?B.burnham:"transparent",display:"flex",alignItems:"center",justifyContent:"center",transition:"all 0.12s"}}>
      <div style={{width:on?9:5,height:on?9:5,borderRadius:"50%",background:on?B.whiteSmoke:B.ash,transition:"all 0.12s"}} /></button>;})}
  </div>;
}
function Sec({label,children}){return<div style={{marginBottom:22}}><div style={{fontSize:10,fontFamily:FU.subtitle,fontWeight:700,letterSpacing:2.5,textTransform:"uppercase",color:B.ash,marginBottom:8}}>{label}</div>{children}</div>;}
function Chip({on,click,children,sm}){return<button onClick={click} style={{padding:sm?"5px 12px":"7px 16px",borderRadius:40,border:`1.5px solid ${on?B.burnham:B.ash+"66"}`,background:on?B.burnham:"transparent",color:on?B.whiteSmoke:B.jet,fontSize:sm?11:13,fontWeight:600,cursor:"pointer",fontFamily:FU.subtitle,letterSpacing:0.5}}>{children}</button>;}
function In({mt,...p}){return<input {...p} style={{width:"100%",padding:"11px 14px",border:`1.5px solid ${B.ash}44`,borderRadius:10,fontSize:14,color:B.jet,outline:"none",boxSizing:"border-box",background:"#FAFAF7",fontFamily:FU.body,marginTop:mt?8:0}} />;}
function Area(p){return<textarea {...p} style={{width:"100%",padding:"11px 14px",border:`1.5px solid ${B.ash}44`,borderRadius:10,fontSize:14,color:B.jet,outline:"none",boxSizing:"border-box",background:"#FAFAF7",fontFamily:FU.body,height:88,resize:"vertical"}} />;}
function Slider({label,min,max,val,set}){return<div style={{display:"flex",alignItems:"center",gap:10,marginBottom:6}}><span style={{fontSize:12,fontFamily:FU.subtitle,fontWeight:500,color:B.ash,minWidth:50}}>{label}</span><input type="range" min={min} max={max} value={val} onChange={e=>set(Number(e.target.value))} style={{flex:1,accentColor:B.burnham}} /><span style={{fontSize:12,fontFamily:FU.body,color:B.ash,minWidth:34}}>{val}%</span></div>;}
